using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketModelService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly string[] _classLabels;
    private readonly EvaluationMetricsResponse _metrics;

    public TicketModelService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Extract class labels before training so we can map scores to names
        _classLabels = _mlContext.Data
            .CreateEnumerable<TicketData>(dataView, reuseRowObject: false)
            .Select(t => t.Category)
            .Distinct()
            .OrderBy(c => c)
            .ToArray();

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);

        _metrics = Evaluate(dataView);
        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    public EvaluationMetricsResponse Metrics => _metrics;

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _classLabels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_classLabels[i]] = prediction.Score[i];
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            Confidence = confidence
        };
    }

    private EvaluationMetricsResponse Evaluate(IDataView dataView)
    {
        // With a small dataset we cross-validate for more reliable metrics
        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(dataView, BuildPipeline(), numberOfFolds: 3, labelColumnName: "Label");

        var best = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First().Metrics;

        var perClass = new List<PerClassMetric>();
        for (var i = 0; i < best.PerClassLogLoss.Count && i < _classLabels.Length; i++)
        {
            perClass.Add(new PerClassMetric
            {
                ClassName = _classLabels[i],
                Precision = i < best.PerClassLogLoss.Count ? 1.0 - best.PerClassLogLoss[i] : 0,
                Recall = 0,
                F1Score = 0
            });
        }

        // Re-evaluate with full training set to get per-class precision/recall
        var predictions = _model.Transform(dataView);
        var fullMetrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        perClass.Clear();
        if (fullMetrics.ConfusionMatrix.PerClassPrecision.Count > 0)
        {
            for (var i = 0; i < fullMetrics.ConfusionMatrix.PerClassPrecision.Count
                           && i < _classLabels.Length; i++)
            {
                perClass.Add(new PerClassMetric
                {
                    ClassName = _classLabels[i],
                    Precision = fullMetrics.ConfusionMatrix.PerClassPrecision[i],
                    Recall = fullMetrics.ConfusionMatrix.PerClassRecall[i],
                    F1Score = 2 * fullMetrics.ConfusionMatrix.PerClassPrecision[i]
                                * fullMetrics.ConfusionMatrix.PerClassRecall[i]
                              / (fullMetrics.ConfusionMatrix.PerClassPrecision[i]
                                 + fullMetrics.ConfusionMatrix.PerClassRecall[i] + 1e-10)
                });
            }
        }

        return new EvaluationMetricsResponse
        {
            MacroAccuracy = (float)fullMetrics.MacroAccuracy,
            MicroAccuracy = (float)fullMetrics.MicroAccuracy,
            LogLoss = (float)fullMetrics.LogLoss,
            LogLossReduction = (float)fullMetrics.LogLossReduction,
            PerClassMetrics = perClass
        };
    }

    private IEstimator<ITransformer> BuildPipeline()
    {
        return _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));
    }
}

